export class Common{constructor(){this.data=[],this.noticesCount=null,this.recCourse=document.getElementById("recommended-courses-name"),this.otherCourse=document.getElementById("other-courses"),this.news=document.getElementById("news"),this.staff=document.getElementById("staff"),this.support=document.getElementById("support"),this.menu=document.querySelector(".menu"),this.menuOpenClose=document.querySelector(".menu-open-close"),this.init()}async init(){this.menuAction(),this.pageActions(),this.data=await this.getData(),this.notices()}async getData(){const t=await fetch("../../data/news.json");return await t.json()}notices(){this.data.forEach(t=>{t.messages.forEach(t=>{t.important&&this.noticesCount++})}),document.querySelectorAll(".notice-count").forEach(t=>{t.innerText=this.noticesCount})}pageActions(){this.recCourse.onclick=()=>{location.href="#/video/"},this.otherCourse.onclick=()=>{location.href="#/choice/"},this.news.onclick=()=>{location.href="#/news/"},this.staff.onclick=()=>{location.href="#/staff/"},this.support.onclick=()=>{location.href="#/support/"}}menuAction(){this.menuOpenClose.onclick=()=>{"block"===this.menu.style.display?this.menu.style.display="none":this.menu.style.display="block"}}}